// Deploy YOUR immutable N-way FeeSplitter through the DeployerFactory on Base.
// Recipients + basis-point shares are fixed FOREVER at deploy — no admin keys, nothing to renounce.
import { createWalletClient, createPublicClient, http, encodeFunctionData, encodeAbiParameters, parseAbi } from "viem";
import { privateKeyToAccount } from "viem/accounts";
import { base } from "viem/chains";
import { readFileSync } from "node:fs";

const FACTORY = "0xCF4357aFdC26fa028e77291CE2F97C9dAF93F75D"; // DeployerFactory on Base (8453)
const CREATION = readFileSync("creation-bytecode.txt", "utf8").trim() as `0x${string}`; // FeeSplitter creation bytecode (this skill folder)

// YOUR split — shares are basis points and MUST sum to exactly 10000:
const RECIPIENTS = ["0x1111111111111111111111111111111111111111", "0x2222222222222222222222222222222222222222"] as `0x${string}`[]; // REPLACE with your addresses
const SHARES_BPS = [7000n, 3000n];

const abi = parseAbi([
  "function deploy(bytes initCode) payable returns (address)",
  "function fee() view returns (uint256)",
  "event Deployed(address indexed deployer, address indexed addr, uint256 feePaid)",
]);
const account = privateKeyToAccount(process.env.PRIVATE_KEY as `0x${string}`);
const pub = createPublicClient({ chain: base, transport: http() });
const wallet = createWalletClient({ account, chain: base, transport: http() });

const ctorTail = encodeAbiParameters([{ type: "address[]" }, { type: "uint256[]" }], [RECIPIENTS, SHARES_BPS]);
const initCode = (CREATION + ctorTail.slice(2)) as `0x${string}`;

const hash = await wallet.sendTransaction({
  to: FACTORY,
  value: await pub.readContract({ address: FACTORY, abi, functionName: "fee" }), // 0 at launch — read, don't assume
  data: encodeFunctionData({ abi, functionName: "deploy", args: [initCode] }),
});
const receipt = await pub.waitForTransactionReceipt({ hash });
const log = receipt.logs.find((l) => l.address.toLowerCase() === FACTORY.toLowerCase());
const splitter = ("0x" + log!.topics[2]!.slice(26)) as `0x${string}`; // Deployed event: topics[2] = new address
console.log("your FeeSplitter:", splitter);

// Route fees: just SEND native ETH or any ERC20 to `splitter`. Payouts are pull-based and permissionless:
const sAbi = parseAbi([
  "function pending(address token, address account) view returns (uint256)",
  "function releaseAll(address token) returns (uint256)",
]);
const NATIVE = "0x0000000000000000000000000000000000000000";
console.log("pending (native, recipient 0):", await pub.readContract({ address: splitter, abi: sAbi, functionName: "pending", args: [NATIVE, RECIPIENTS[0]] }));
// later, anyone: wallet.writeContract({ address: splitter, abi: sAbi, functionName: "releaseAll", args: [NATIVE] })
